const listWorkflowRecordsPage = `-- name: ListWorkflowRecordsPage :many
WITH workflow_list(
    id,
    name,
    description,
    version,
    created_at_unix_ms,
    updated_at_unix_ms,
    activity_at_unix_ms
) AS (
    SELECT
        workflows.id,
        workflows.name,
        workflows.description,
        workflows.version,
        workflows.created_at_unix_ms,
        workflows.updated_at_unix_ms,
        CAST(MAX(
            workflows.updated_at_unix_ms,
            COALESCE((
                SELECT MAX(task_records.updated_at_unix_ms)
                FROM task_records
                WHERE task_records.workflow_id = workflows.id
            ), 0)
        ) AS INTEGER) AS activity_at_unix_ms
    FROM workflows
    WHERE (?2 = '' OR workflows.name = ?2)
      AND (
          ?3 = ''
          OR lower(workflows.name) LIKE '%' || lower(?3) || '%'
          OR lower(workflows.description) LIKE '%' || lower(?3) || '%'
      )
      AND (
          ?4 = 0
          OR MAX(
              workflows.updated_at_unix_ms,
              COALESCE((
                  SELECT MAX(task_records.updated_at_unix_ms)
                  FROM task_records
                  WHERE task_records.workflow_id = workflows.id
              ), 0)
          ) < ?5
          OR (
              MAX(
                  workflows.updated_at_unix_ms,
                  COALESCE((
                      SELECT MAX(task_records.updated_at_unix_ms)
                      FROM task_records
                      WHERE task_records.workflow_id = workflows.id
                  ), 0)
              ) = ?5
              AND workflows.id < ?6
          )
      )
)
SELECT
    id,
    name,
    description,
    version,
    created_at_unix_ms,
    updated_at_unix_ms,
    activity_at_unix_ms
FROM workflow_list
ORDER BY activity_at_unix_ms DESC, id DESC
LIMIT ?1
`

